func (c *core) execute(ctx context.Context, client *Client, req *Request) (*Response, error) {

	c.ctx = ctx
	c.client = client
	c.req = req

	err := c.preHooks()
	if err != nil {
		return nil, err
	}

	cancel := c.timeout()
	if cancel != nil {
		defer cancel()
	}

	resp, err := c.execFunc()
	if err != nil {
		return nil, err
	}

	err = c.afterHooks(resp)
	if err != nil {
		resp.Close()
		return nil, err
	}

	return resp, nil
}
